import { useRef, useState, useEffect } from 'preact/hooks';
import { configs } from './configs';

export function FootnoteRenderer(props) {
	const fnRef = useRef(null);
	const [isOpen, setIsOpen] = useState(false);


	useEffect(() => { 
		if (fnRef.current) {
			if (props.cons === '') {
				fnRef.current.style.visibility = 'hidden';
				fnRef.current.style.display = 'none';
				setIsOpen(false);
			} else {
				fnRef.current.style.visibility = 'visible';
				fnRef.current.style.display = 'block';
				setIsOpen(true);
			}
		}
	}, [props.cons]);

	/*const wrapper = document.getElementById('fnglo-wrapper');


	window.onclick = (e) => {
		console.log("checking to close fn viewer")
		if (wrapper !== e.target && !wrapper.contains(e.target) && isOpen) {
			props.closeFnViewer();
		}
	}; */


	return (
			<div 
				id="fnglo-wrapper" 
				ref={fnRef}
				style="visibility:hidden;display:none;">
                    <div class="mdl-card__title" style="display: flex; justify-content:center;">
                        <h2 class="mdl-card__title-text" style="text-align:center;">{ props.title }</h2>
                    </div>
				<div class="mdl-card__supporting-text" >
					{props.cons}
				</div>
                <div class="mdl-card__actions mdl-card--border">
                    <a class="mdl-button mdl-button--colored mdl-js-button mdl-js-ripple-effect"
                        onclick={props.closeFnViewer}>
                        { configs.close }
                    </a>
                </div>
			</div>
	);

}